sql:
SELECT COUNT(DISTINCT model_id) AS completed_model_count
FROM training_runs
WHERE status = 'completed';

SELECT created_by, COUNT(model_id) AS total_models
FROM models
GROUP BY created_by;

external_knowledge:
- "best performers" refers to models with the highest average accuracy; 
- "median performance in terms of accuracy" here is a vague term used for "average accuracy" to maintain some ambiguity, indicating the typical performance of a model;
- "top five models overall" refers to the top five models when sorted by average accuracy.

sql:
